import{_ as r,o,c as i,al as t}from"./chunks/framework.BAfiqLBo.js";const p=JSON.parse('{"title":"Mises à jour du Firmware (DFU)","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/dfu.md","filePath":"fr/guide/dfu.md"}'),a={name:"fr/guide/dfu.md"};function n(s,e,u,l,d,c){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="mises-a-jour-du-firmware-dfu" tabindex="-1">Mises à jour du Firmware (DFU) <a class="header-anchor" href="#mises-a-jour-du-firmware-dfu" aria-label="Permalink to &quot;Mises à jour du Firmware (DFU)&quot;">​</a></h1><p>Les appareils Boks peuvent être mis à jour sans fil via le protocole <strong>Device Firmware Update (DFU)</strong> en Bluetooth. Cela permet au matériel de recevoir des corrections de bugs et de nouvelles fonctionnalités.</p><h2 id="securite-protection" tabindex="-1">Sécurité &amp; Protection <a class="header-anchor" href="#securite-protection" aria-label="Permalink to &quot;Sécurité &amp; Protection&quot;">​</a></h2><p>Le système de mise à jour de la Boks est conçu pour être <strong>protégé</strong>. Le matériel utilise des paquets de firmware signés ; si un utilisateur tente d&#39;envoyer un paquet de mise à jour falsifié ou invalide, la Boks refusera de l&#39;installer.</p><h2 id="⚠️-avertissement-critique-pour-boks-v3-non-nfc-nrf52811" tabindex="-1">⚠️ Avertissement Critique pour Boks V3 (Non-NFC / nRF52811) <a class="header-anchor" href="#⚠️-avertissement-critique-pour-boks-v3-non-nfc-nrf52811" aria-label="Permalink to &quot;⚠️ Avertissement Critique pour Boks V3 (Non-NFC / nRF52811)&quot;">​</a></h2><p>Si vous possédez une <strong>Boks Non-NFC</strong> (également appelée Boks V3, fonctionnant sur une puce nRF52811), veuillez lire attentivement ce qui suit :</p><ul><li><strong>Une mise à jour invalide ou interrompue supprimera le logiciel précédent.</strong></li><li>Dans ce cas, la Boks restera bloquée en &quot;Mode DFU&quot; (bootloader) en attendant une mise à jour logicielle valide et <strong>ne redémarrera jamais</strong> sur l&#39;ancienne version.</li><li>Vous devrez impérativement fournir un fichier de firmware valide pour restaurer le fonctionnement.</li></ul><p>Ce comportement est différent de la <strong>Boks NFC</strong> (V4 / nRF52833), qui peut redémarrer en toute sécurité sur son ancien logiciel si une mise à jour échoue.</p><h2 id="comment-mettre-a-jour" tabindex="-1">Comment mettre à jour <a class="header-anchor" href="#comment-mettre-a-jour" aria-label="Permalink to &quot;Comment mettre à jour&quot;">​</a></h2><h3 id="utilisation-du-sdk" tabindex="-1">Utilisation du SDK <a class="header-anchor" href="#utilisation-du-sdk" aria-label="Permalink to &quot;Utilisation du SDK&quot;">​</a></h3><p>Le SDK Boks lui-même n&#39;inclut pas encore de client DFU intégré. Cependant, vous pouvez utiliser les fichiers de firmware récupérés via le SDK avec des outils standards.</p><h3 id="mise-a-jour-manuelle-secours" tabindex="-1">Mise à jour manuelle (Secours) <a class="header-anchor" href="#mise-a-jour-manuelle-secours" aria-label="Permalink to &quot;Mise à jour manuelle (Secours)&quot;">​</a></h3><p>Si vous disposez du paquet <code>.zip</code> du firmware :</p><ol><li>Installez l&#39;application <strong>nRF Connect for Mobile</strong> (disponible sur Android et iOS).</li><li>Mettez votre Boks en mode DFU (cela se produit automatiquement lorsqu&#39;un processus DFU est initié, ou après une mise à jour échouée).</li><li>Connectez-vous à l&#39;appareil (généralement nommé <code>DfuTarg</code> ou <code>Boks_DFU</code>).</li><li>Téléchargez le fichier <code>.zip</code> du firmware en utilisant le bouton DFU de l&#39;application.</li></ol>',14)])])}const f=r(a,[["render",n]]);export{p as __pageData,f as default};
